function SnakeGame() {
  const [snake, setSnake] = React.useState([{x:10,y:10}]);
  const [food, setFood] = React.useState({x:15,y:15});
  const [dir, setDir] = React.useState({x:1,y:0});
  const [score, setScore] = React.useState(0);
  const [high, setHigh] = React.useState(0);
  const [over, setOver] = React.useState(false);
  const [running, setRunning] = React.useState(false);
  const canvasRef = React.useRef(null);

  const rand = ()=>({x:Math.floor(Math.random()*20),y:Math.floor(Math.random()*20)});

  React.useEffect(()=>{
    if(!running||over)return;
    const id = setInterval(()=>{
      setSnake(prev=>{
        const head = {x:prev[0].x+dir.x,y:prev[0].y+dir.y};
        if(head.x<0||head.x>=20||head.y<0||head.y>=20||prev.some(s=>s.x===head.x&&s.y===head.y)){
          setOver(true);setRunning(false);setHigh(h=>Math.max(h,score));return prev;
        }
        const next = [head,...prev];
        if(head.x===food.x&&head.y===food.y){setScore(s=>s+10);setFood(rand());}
        else next.pop();
        return next;
      });
    },150);
    return ()=>clearInterval(id);
  },[running,over,dir,food,score]);

  React.useEffect(()=>{
    const c = canvasRef.current; if(!c)return;
    const ctx = c.getContext('2d');
    ctx.fillStyle='#000';ctx.fillRect(0,0,300,300);
    ctx.fillStyle='#34C759';
    snake.forEach(s=>ctx.fillRect(s.x*15,s.y*15,14,14));
    ctx.fillStyle='#FF3B30';ctx.fillRect(food.x*15,food.y*15,14,14);
  },[snake,food]);

  const key = (e)=>{
    const k = e.key;
    if(k==='ArrowUp'&&dir.y!==1)setDir({x:0,y:-1});
    if(k==='ArrowDown'&&dir.y!==-1)setDir({x:0,y:1});
    if(k==='ArrowLeft'&&dir.x!==1)setDir({x:-1,y:0});
    if(k==='ArrowRight'&&dir.x!==-1)setDir({x:1,y:0});
  };

  React.useEffect(()=>{window.addEventListener('keydown',key);return()=>window.removeEventListener('keydown',key);},[dir]);

  const restart = ()=>{setSnake([{x:10,y:10}]);setFood(rand());setDir({x:1,y:0});setScore(0);setOver(false);setRunning(true);};

  return (
    <div style={{padding:12,fontFamily:'system-ui',display:'flex',flexDirection:'column',alignItems:'center',height:'100%'}}>
      <div style={{display:'flex',justifyContent:'space-between',width:300,marginBottom:8}}>
        <span style={{fontSize:14,fontWeight:700}}>Score: {score}</span>
        <span style={{fontSize:14,color:'#888'}}>High: {high}</span>
      </div>
      <canvas ref={canvasRef} width={300} height={300} style={{borderRadius:8,background:'#000'}}/>
      <div style={{marginTop:12}}>
        {!running&&!over&&<button onClick={()=>setRunning(true)} style={{padding:'8px 20px',borderRadius:8,background:'#34C759',color:'#fff',border:'none',cursor:'pointer'}}>Start</button>}
        {over&&<button onClick={restart} style={{padding:'8px 20px',borderRadius:8,background:'#FF3B30',color:'#fff',border:'none',cursor:'pointer'}}>Game Over — Retry</button>}
        {running&&<button onClick={()=>setRunning(false)} style={{padding:'8px 20px',borderRadius:8,background:'#888',color:'#fff',border:'none',cursor:'pointer'}}>Pause</button>}
      </div>
      <div style={{fontSize:11,color:'#aaa',marginTop:8}}>Use arrow keys to move</div>
    </div>
  );
}
render(<SnakeGame/>);
